22	
23	export type IrcNickServConfig = {
24	  enabled?: boolean;
25	  service?: string;
26	  password?: string;
27	  passwordFile?: string;
28	  register?: boolean;
29	  registerEmail?: string;
30	};
31	
32	export type IrcAccountConfig = {
33	  name?: string;
34	  enabled?: boolean;
35	  /**
36	   * Break-glass override: allow nick-only allowlist matching.
37	   * Default behavior requires host/user-qualified identities.
38	   */
39	  dangerouslyAllowNameMatching?: boolean;
40	  host?: string;
41	  port?: number;
42	  tls?: boolean;
43	  nick?: string;
44	  username?: string;
45	  realname?: string;
46	  password?: string;
47	  passwordFile?: string;
48	  nickserv?: IrcNickServConfig;
49	  dmPolicy?: DmPolicy;
50	  allowFrom?: Array<string | number>;
51	  defaultTo?: string;
52	  groupPolicy?: GroupPolicy;
53	  groupAllowFrom?: Array<string | number>;
54	  groups?: Record<string, IrcChannelConfig>;
55	  channels?: string[];
56	  mentionPatterns?: string[];
57	  markdown?: MarkdownConfig;
58	  historyLimit?: number;
59	  dmHistoryLimit?: number;
60	  dms?: Record<string, DmConfig>;
61	  textChunkLimit?: number;
62	  chunkMode?: "length" | "newline";
63	  blockStreaming?: boolean;
64	  blockStreamingCoalesce?: BlockStreamingCoalesceConfig;
65	  responsePrefix?: string;
66	  mediaMaxMb?: number;
67	};
68	
69	export type IrcConfig = IrcAccountConfig & {
70	  accounts?: Record<string, IrcAccountConfig>;
71	  defaultAccount?: string;
72	};
73	
74	export type CoreConfig = OpenClawConfig & {
75	  channels?: OpenClawConfig["channels"] & {
76	    irc?: IrcConfig;
77	  };
78	};
79	
80	export type IrcInboundMessage = {
81	  messageId: string;
82	  /** Conversation peer id: channel name for groups, sender nick for DMs. */
83	  target: string;
84	  /** Raw IRC PRIVMSG target (bot nick for DMs, channel for groups). */
85	  rawTarget?: string;
86	  senderNick: string;
87	  senderUser?: string;
88	  senderHost?: string;
89	  text: string;
90	  timestamp: number;
91	  isGroup: boolean;
92	};
