310	function resolveTelegramOutboundSessionRoute(params: {
311	  cfg: OpenClawConfig;
312	  agentId: string;
313	  accountId?: string | null;
314	  target: string;
315	  resolvedTarget?: { kind: string };
316	  threadId?: string | number | null;
317	}) {
318	  const parsed = parseTelegramTarget(params.target);
319	  const chatId = parsed.chatId.trim();
320	  if (!chatId) {
321	    return null;
322	  }
323	  const fallbackThreadId = normalizeOutboundThreadId(params.threadId);
324	  const resolvedThreadId = parsed.messageThreadId ?? parseTelegramThreadId(fallbackThreadId);
325	  const isGroup =
326	    parsed.chatType === "group" ||
327	    (parsed.chatType === "unknown" &&
328	      params.resolvedTarget?.kind &&
329	      params.resolvedTarget.kind !== "user");
330	  const peerId =
331	    isGroup && resolvedThreadId ? buildTelegramGroupPeerId(chatId, resolvedThreadId) : chatId;
332	  const peer: RoutePeer = {
333	    kind: isGroup ? "group" : "direct",
334	    id: peerId,
335	  };
336	  const baseSessionKey = buildTelegramBaseSessionKey({
337	    cfg: params.cfg,
338	    agentId: params.agentId,
339	    accountId: params.accountId,
340	    peer,
341	  });
342	  const threadKeys =
343	    resolvedThreadId && !isGroup
344	      ? resolveThreadSessionKeys({ baseSessionKey, threadId: String(resolvedThreadId) })
345	      : null;
346	  return {
347	    sessionKey: threadKeys?.sessionKey ?? baseSessionKey,
348	    baseSessionKey,
349	    peer,
350	    chatType: isGroup ? ("group" as const) : ("direct" as const),
351	    from: isGroup
352	      ? `telegram:group:${peerId}`
353	      : resolvedThreadId
354	        ? `telegram:${chatId}:topic:${resolvedThreadId}`
355	        : `telegram:${chatId}`,
356	    to: `telegram:${chatId}`,
357	    threadId: resolvedThreadId,
358	  };
359	}
