import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

/** Minimal resolved-account shape used by the config adapter. */
type PulseBoardResolvedAccount = {
  accountId: string;
  configured: boolean;
};

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin<PulseBoardResolvedAccount>({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (_cfg) => [],
      resolveAccount: (_cfg, accountId) => ({
        accountId: accountId ?? "default",
        configured: false,
      }),
      isConfigured: (account) => account.configured,
    },
    setup: {
      // Stub: return config unchanged until real account provisioning is implemented.
      applyAccountConfig: ({ cfg }) => cfg,
    },
    messaging: {
      normalizeTarget: (raw) => raw.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[pulseboard] connecting account "${ctx.accountId}"...`);
      },
    },
  },
  outbound: {
    base: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
    },
    attachedResults: {
      channel: "pulseboard",
      // Stub: log the outbound send and return a synthetic message ID.
      sendText: async ({ to }) => {
        const messageId = `pb-${Date.now()}`;
        return { messageId, channelId: to };
      },
    },
  },
});

